    public class IndexedAttestation
    {
        public ulong[] AttestingIndices;
        public AttestationData Data;
        public Bytes96 Signature;

        public IndexedAttestation()
        {
            Data = new AttestationData();
            Signature = new Bytes96();
        }

        public int SszBytesLen()
        {
            int size = 228;
            size += AttestingIndices.Length * 8;
            return size;
        }

        public byte[] MarshalSSZ()
        {
            byte[] buf = new byte[SszBytesLen()];
            MarshalSSZTo(buf);
            return buf;
        }

        public void MarshalSSZTo(Span<byte> buf)
        {
            int offset = 0;
            int fixedStart = offset;

            // Offset placeholder for 'attesting_indices'
            int offsetPos0 = offset;
            offset += 4;
            // Field 'data'
            Data.MarshalSSZTo(buf.Slice(offset));
            offset += 128;
            // Field 'signature'
            Signature.MarshalSSZTo(buf.Slice(offset));
            offset += 96;

            // Dynamic field 'attesting_indices'
            BinaryPrimitives.WriteUInt32LittleEndian(buf.Slice(offsetPos0), (uint)(offset - fixedStart));
            for (int i = 0; i < AttestingIndices.Length; i++)
            {
                BinaryPrimitives.WriteUInt64LittleEndian(buf.Slice(offset), AttestingIndices[i]);
                offset += 8;
            }
        }

        public static IndexedAttestation FromSSZBytes(ReadOnlySpan<byte> bytes)
        {
            if (bytes.Length < 228)
                throw new SszError("buffer too small");

            var t = new IndexedAttestation();
            int offset = 0;

            int dynOffset0 = (int)BinaryPrimitives.ReadUInt32LittleEndian(bytes.Slice(offset));
            offset += 4;
            if (dynOffset0 != 228)
                throw new SszError("invalid offset");
            t.Data = AttestationData.FromSSZBytes(bytes.Slice(offset, 128));
            offset += 128;
            t.Signature = Bytes96.FromSSZBytes(bytes.Slice(offset, 96));
            offset += 96;

            {
                var dynBuf = bytes.Slice(dynOffset0, bytes.Length - dynOffset0);
                {
                    int count = dynBuf.Length / 8;
                    t.AttestingIndices = new ulong[count];
                    for (int i = 0; i < count; i++)
                    {
                        int off = i * 8;
                        t.AttestingIndices[i] = BinaryPrimitives.ReadUInt64LittleEndian(dynBuf.Slice(off));
                    }
                }
            }

            return t;
        }

        public byte[] HashTreeRoot()
        {
            var hh = Hasher.New();
            int idx = hh.Index();

            // Field 'attesting_indices'
            {
                int subIdx = hh.Index();
                for (int i = 0; i < AttestingIndices.Length; i++)
                    hh.AppendUint64(AttestingIndices[i]);
                hh.FillUpTo32();
                hh.MerkleizeWithMixin(subIdx, (ulong)AttestingIndices.Length, 512);
            }

            // Field 'data'
            Data.HashTreeRootWith(hh);

            // Field 'signature'
            Signature.HashTreeRootWith(hh);

            hh.Merkleize(idx);
            return hh.HashRoot();
        }
    }

    public class AttesterSlashing
    {
        public IndexedAttestation Attestation1;
        public IndexedAttestation Attestation2;

        public AttesterSlashing()
        {
            Attestation1 = new IndexedAttestation();
            Attestation2 = new IndexedAttestation();
        }

        public int SszBytesLen()
        {
            int size = 8;
            size += Attestation1.SszBytesLen();
            size += Attestation2.SszBytesLen();
            return size;
        }

        public byte[] MarshalSSZ()
        {
            byte[] buf = new byte[SszBytesLen()];
            MarshalSSZTo(buf);
            return buf;
        }

        public void MarshalSSZTo(Span<byte> buf)
        {
            int offset = 0;
            int fixedStart = offset;

            // Offset placeholder for 'attestation_1'
            int offsetPos0 = offset;
            offset += 4;
            // Offset placeholder for 'attestation_2'
            int offsetPos1 = offset;
            offset += 4;

            // Dynamic field 'attestation_1'
            BinaryPrimitives.WriteUInt32LittleEndian(buf.Slice(offsetPos0), (uint)(offset - fixedStart));
            Attestation1.MarshalSSZTo(buf.Slice(offset));
            offset += 0;
            // Dynamic field 'attestation_2'
            BinaryPrimitives.WriteUInt32LittleEndian(buf.Slice(offsetPos1), (uint)(offset - fixedStart));
            Attestation2.MarshalSSZTo(buf.Slice(offset));
            offset += 0;
        }

        public static AttesterSlashing FromSSZBytes(ReadOnlySpan<byte> bytes)
        {
            if (bytes.Length < 8)
                throw new SszError("buffer too small");

            var t = new AttesterSlashing();
            int offset = 0;

            int dynOffset0 = (int)BinaryPrimitives.ReadUInt32LittleEndian(bytes.Slice(offset));
            offset += 4;
            if (dynOffset0 != 8)
                throw new SszError("invalid offset");
            int dynOffset1 = (int)BinaryPrimitives.ReadUInt32LittleEndian(bytes.Slice(offset));
            offset += 4;
            if (dynOffset1 < dynOffset0 || dynOffset1 > bytes.Length)
                throw new SszError("invalid offset");

            {
                var dynBuf = bytes.Slice(dynOffset0, dynOffset1 - dynOffset0);
                t.Attestation1 = IndexedAttestation.FromSSZBytes(dynBuf);
            }
            {
                var dynBuf = bytes.Slice(dynOffset1, bytes.Length - dynOffset1);
                t.Attestation2 = IndexedAttestation.FromSSZBytes(dynBuf);
            }

            return t;
        }

        public byte[] HashTreeRoot()
        {
            var hh = Hasher.New();
            int idx = hh.Index();

            // Field 'attestation_1'
            Attestation1.HashTreeRootWith(hh);

            // Field 'attestation_2'
            Attestation2.HashTreeRootWith(hh);

            hh.Merkleize(idx);
            return hh.HashRoot();
        }
    }

    public class Attestation
    {
        public byte[] AggregationBits;
        public AttestationData Data;
        public Bytes96 Signature;

        public Attestation()
        {
            Data = new AttestationData();
            Signature = new Bytes96();
        }

        public int SszBytesLen()
        {
            int size = 228;
            size += AggregationBits.Length;
            return size;
        }

        public byte[] MarshalSSZ()
        {
            byte[] buf = new byte[SszBytesLen()];
            MarshalSSZTo(buf);
            return buf;
        }

        public void MarshalSSZTo(Span<byte> buf)
        {
            int offset = 0;
            int fixedStart = offset;

            // Offset placeholder for 'aggregation_bits'
            int offsetPos0 = offset;
            offset += 4;
            // Field 'data'
            Data.MarshalSSZTo(buf.Slice(offset));
            offset += 128;
            // Field 'signature'
            Signature.MarshalSSZTo(buf.Slice(offset));
            offset += 96;

            // Dynamic field 'aggregation_bits'
            BinaryPrimitives.WriteUInt32LittleEndian(buf.Slice(offsetPos0), (uint)(offset - fixedStart));
            AggregationBits.AsSpan().CopyTo(buf.Slice(offset));
            offset += AggregationBits.Length;
        }

        public static Attestation FromSSZBytes(ReadOnlySpan<byte> bytes)
        {
            if (bytes.Length < 228)
                throw new SszError("buffer too small");

            var t = new Attestation();
            int offset = 0;

            int dynOffset0 = (int)BinaryPrimitives.ReadUInt32LittleEndian(bytes.Slice(offset));
            offset += 4;
            if (dynOffset0 != 228)
                throw new SszError("invalid offset");
            t.Data = AttestationData.FromSSZBytes(bytes.Slice(offset, 128));
            offset += 128;
            t.Signature = Bytes96.FromSSZBytes(bytes.Slice(offset, 96));
            offset += 96;

            {
                var dynBuf = bytes.Slice(dynOffset0, bytes.Length - dynOffset0);
                t.AggregationBits = dynBuf.ToArray();
            }

            return t;
        }

        public byte[] HashTreeRoot()
        {
            var hh = Hasher.New();
            int idx = hh.Index();

            // Field 'aggregation_bits'
            hh.PutBitlist(AggregationBits, 2048);

            // Field 'data'
            Data.HashTreeRootWith(hh);

            // Field 'signature'
            Signature.HashTreeRootWith(hh);

            hh.Merkleize(idx);
            return hh.HashRoot();
        }
    }

    public class ExecutionPayload
    {
        public Bytes32 ParentHash;
        public Bytes20 FeeRecipient;
        public Bytes32 StateRoot;
        public Bytes32 ReceiptsRoot;
        public Bytes256 LogsBloom;
        public Bytes32 PrevRandao;
        public ulong BlockNumber;
        public ulong GasLimit;
        public ulong GasUsed;
        public ulong Timestamp;
        public byte[] ExtraData;
        public Bytes32 BaseFeePerGas;
        public Bytes32 BlockHash;
        public List<byte[]> Transactions;
        public List<Withdrawal> Withdrawals;
        public ulong BlobGasUsed;
        public ulong ExcessBlobGas;

        public ExecutionPayload()
        {
            ParentHash = new Bytes32();
            FeeRecipient = new Bytes20();
            StateRoot = new Bytes32();
            ReceiptsRoot = new Bytes32();
            LogsBloom = new Bytes256();
            PrevRandao = new Bytes32();
            BaseFeePerGas = new Bytes32();
            BlockHash = new Bytes32();
        }

        public int SszBytesLen()
        {
            int size = 528;
            size += ExtraData.Length;
            size += Transactions.Count * 4;
            foreach (var item in Transactions)
                size += item.Length;
            size += Withdrawals.Count * 44;
            return size;
        }

        public byte[] MarshalSSZ()
        {
            byte[] buf = new byte[SszBytesLen()];
            MarshalSSZTo(buf);
            return buf;
        }

        public void MarshalSSZTo(Span<byte> buf)
        {
            int offset = 0;
            int fixedStart = offset;

            // Field 'parent_hash'
            ParentHash.MarshalSSZTo(buf.Slice(offset));
            offset += 32;
            // Field 'fee_recipient'
            FeeRecipient.MarshalSSZTo(buf.Slice(offset));
            offset += 20;
            // Field 'state_root'
            StateRoot.MarshalSSZTo(buf.Slice(offset));
            offset += 32;
            // Field 'receipts_root'
            ReceiptsRoot.MarshalSSZTo(buf.Slice(offset));
            offset += 32;
            // Field 'logs_bloom'
            LogsBloom.MarshalSSZTo(buf.Slice(offset));
            offset += 256;
            // Field 'prev_randao'
            PrevRandao.MarshalSSZTo(buf.Slice(offset));
            offset += 32;
            // Field 'block_number'
            BinaryPrimitives.WriteUInt64LittleEndian(buf.Slice(offset), BlockNumber);
            offset += 8;
            // Field 'gas_limit'
            BinaryPrimitives.WriteUInt64LittleEndian(buf.Slice(offset), GasLimit);
            offset += 8;
            // Field 'gas_used'
            BinaryPrimitives.WriteUInt64LittleEndian(buf.Slice(offset), GasUsed);
            offset += 8;
            // Field 'timestamp'
            BinaryPrimitives.WriteUInt64LittleEndian(buf.Slice(offset), Timestamp);
            offset += 8;
            // Offset placeholder for 'extra_data'
            int offsetPos0 = offset;
            offset += 4;
            // Field 'base_fee_per_gas'
            BaseFeePerGas.MarshalSSZTo(buf.Slice(offset));
            offset += 32;
            // Field 'block_hash'
            BlockHash.MarshalSSZTo(buf.Slice(offset));
            offset += 32;
            // Offset placeholder for 'transactions'
            int offsetPos1 = offset;
            offset += 4;
            // Offset placeholder for 'withdrawals'
            int offsetPos2 = offset;
            offset += 4;
            // Field 'blob_gas_used'
            BinaryPrimitives.WriteUInt64LittleEndian(buf.Slice(offset), BlobGasUsed);
            offset += 8;
            // Field 'excess_blob_gas'
            BinaryPrimitives.WriteUInt64LittleEndian(buf.Slice(offset), ExcessBlobGas);
            offset += 8;

            // Dynamic field 'extra_data'
            BinaryPrimitives.WriteUInt32LittleEndian(buf.Slice(offsetPos0), (uint)(offset - fixedStart));
            ExtraData.AsSpan().CopyTo(buf.Slice(offset));
            offset += ExtraData.Length;
            // Dynamic field 'transactions'
            BinaryPrimitives.WriteUInt32LittleEndian(buf.Slice(offsetPos1), (uint)(offset - fixedStart));
            {
                int listStart = offset;
                for (int i = 0; i < Transactions.Count; i++)
                    offset += 4;
                for (int i = 0; i < Transactions.Count; i++)
                {
                    BinaryPrimitives.WriteUInt32LittleEndian(buf.Slice(listStart + i * 4), (uint)(offset - listStart));
                    Transactions[i].AsSpan().CopyTo(buf.Slice(offset));
                    offset += Transactions[i].Length;
                }
            }
            // Dynamic field 'withdrawals'
            BinaryPrimitives.WriteUInt32LittleEndian(buf.Slice(offsetPos2), (uint)(offset - fixedStart));
            foreach (var item in Withdrawals)
            {
                item.MarshalSSZTo(buf.Slice(offset));
                offset += 44;
            }
        }

        public static ExecutionPayload FromSSZBytes(ReadOnlySpan<byte> bytes)
        {
            if (bytes.Length < 528)
                throw new SszError("buffer too small");

            var t = new ExecutionPayload();
            int offset = 0;

            t.ParentHash = Bytes32.FromSSZBytes(bytes.Slice(offset, 32));
            offset += 32;
            t.FeeRecipient = Bytes20.FromSSZBytes(bytes.Slice(offset, 20));
            offset += 20;
            t.StateRoot = Bytes32.FromSSZBytes(bytes.Slice(offset, 32));
            offset += 32;
            t.ReceiptsRoot = Bytes32.FromSSZBytes(bytes.Slice(offset, 32));
            offset += 32;
            t.LogsBloom = Bytes256.FromSSZBytes(bytes.Slice(offset, 256));
            offset += 256;
            t.PrevRandao = Bytes32.FromSSZBytes(bytes.Slice(offset, 32));
            offset += 32;
            t.BlockNumber = BinaryPrimitives.ReadUInt64LittleEndian(bytes.Slice(offset));
            offset += 8;
            t.GasLimit = BinaryPrimitives.ReadUInt64LittleEndian(bytes.Slice(offset));
            offset += 8;
            t.GasUsed = BinaryPrimitives.ReadUInt64LittleEndian(bytes.Slice(offset));
            offset += 8;
            t.Timestamp = BinaryPrimitives.ReadUInt64LittleEndian(bytes.Slice(offset));
            offset += 8;
            int dynOffset0 = (int)BinaryPrimitives.ReadUInt32LittleEndian(bytes.Slice(offset));
            offset += 4;
            if (dynOffset0 != 528)
                throw new SszError("invalid offset");
            t.BaseFeePerGas = Bytes32.FromSSZBytes(bytes.Slice(offset, 32));
            offset += 32;
            t.BlockHash = Bytes32.FromSSZBytes(bytes.Slice(offset, 32));
            offset += 32;
            int dynOffset1 = (int)BinaryPrimitives.ReadUInt32LittleEndian(bytes.Slice(offset));
            offset += 4;
            if (dynOffset1 < dynOffset0 || dynOffset1 > bytes.Length)
                throw new SszError("invalid offset");
            int dynOffset2 = (int)BinaryPrimitives.ReadUInt32LittleEndian(bytes.Slice(offset));
            offset += 4;
            if (dynOffset2 < dynOffset1 || dynOffset2 > bytes.Length)
                throw new SszError("invalid offset");
            t.BlobGasUsed = BinaryPrimitives.ReadUInt64LittleEndian(bytes.Slice(offset));
            offset += 8;
            t.ExcessBlobGas = BinaryPrimitives.ReadUInt64LittleEndian(bytes.Slice(offset));
            offset += 8;

            {
                var dynBuf = bytes.Slice(dynOffset0, dynOffset1 - dynOffset0);
                t.ExtraData = dynBuf.ToArray();
            }
            {
                var dynBuf = bytes.Slice(dynOffset1, dynOffset2 - dynOffset1);
                if (dynBuf.Length > 0)
                {
                    int firstOff = (int)BinaryPrimitives.ReadUInt32LittleEndian(dynBuf);
                    if (firstOff % 4 != 0)
                        throw new SszError("invalid offset");
                    int count = firstOff / 4;
                    t.Transactions = new List<byte[]>(count);
                    for (int i = 0; i < count; i++)
                    {
                        int start = (int)BinaryPrimitives.ReadUInt32LittleEndian(dynBuf.Slice(i * 4));
                        int end = (i + 1 < count) ? (int)BinaryPrimitives.ReadUInt32LittleEndian(dynBuf.Slice((i + 1) * 4)) : dynBuf.Length;
                        if (start > end || end > dynBuf.Length)
                            throw new SszError("invalid offset");
                        t.Transactions.Add(dynBuf.Slice(start, end - start).ToArray());
                    }
                }
                else
                {
                    t.Transactions = new List<byte[]>();
                }
            }
            {
                var dynBuf = bytes.Slice(dynOffset2, bytes.Length - dynOffset2);
                {
                    int count = dynBuf.Length / 44;
                    t.Withdrawals = new List<Withdrawal>(count);
                    for (int i = 0; i < count; i++)
                    {
                        int off = i * 44;
                        t.Withdrawals.Add(Withdrawal.FromSSZBytes(dynBuf.Slice(off, 44)));
                    }
                }
            }

            return t;
        }

        public byte[] HashTreeRoot()
        {
            var hh = Hasher.New();
            int idx = hh.Index();

            // Field 'parent_hash'
            ParentHash.HashTreeRootWith(hh);

            // Field 'fee_recipient'
            FeeRecipient.HashTreeRootWith(hh);

            // Field 'state_root'
            StateRoot.HashTreeRootWith(hh);

            // Field 'receipts_root'
            ReceiptsRoot.HashTreeRootWith(hh);

            // Field 'logs_bloom'
            LogsBloom.HashTreeRootWith(hh);

            // Field 'prev_randao'
            PrevRandao.HashTreeRootWith(hh);

            // Field 'block_number'
            hh.PutUint64(BlockNumber);

            // Field 'gas_limit'
            hh.PutUint64(GasLimit);

            // Field 'gas_used'
            hh.PutUint64(GasUsed);

            // Field 'timestamp'
            hh.PutUint64(Timestamp);

            // Field 'extra_data'
            {
                int subIdx = hh.Index();
                hh.AppendBytes32(ExtraData);
                hh.MerkleizeWithMixin(subIdx, (ulong)ExtraData.Length, 1);
            }

            // Field 'base_fee_per_gas'
            BaseFeePerGas.HashTreeRootWith(hh);

            // Field 'block_hash'
            BlockHash.HashTreeRootWith(hh);

            // Field 'transactions'
            {
                int subIdx = hh.Index();
                foreach (var item in Transactions)
                {
                    int inner = hh.Index();
                    hh.AppendBytes32(item);
                    hh.MerkleizeWithMixin(inner, (ulong)item.Length, 33554432);
                }
                hh.MerkleizeWithMixin(subIdx, (ulong)Transactions.Count, 1048576);
            }

            // Field 'withdrawals'
            {
                int subIdx = hh.Index();
                foreach (var item in Withdrawals)
                    item.HashTreeRootWith(hh);
                hh.MerkleizeWithMixin(subIdx, (ulong)Withdrawals.Count, 16);
            }

            // Field 'blob_gas_used'
            hh.PutUint64(BlobGasUsed);

            // Field 'excess_blob_gas'
            hh.PutUint64(ExcessBlobGas);

            hh.Merkleize(idx);
            return hh.HashRoot();
        }
    }

