        public int SszBytesLen()
        {
            int size = 392;
            size += ProposerSlashings.Count * 416;
            size += AttesterSlashings.Count * 4;
            foreach (var item in AttesterSlashings)
                size += item.SszBytesLen();
            size += Attestations.Count * 4;
            foreach (var item in Attestations)
                size += item.SszBytesLen();
            size += Deposits.Count * 1240;
            size += VoluntaryExits.Count * 112;
            size += ExecutionPayload.SszBytesLen();
            size += BlsToExecutionChanges.Count * 172;
            size += BlobKzgCommitments.Count * 48;
            return size;
        }

        public byte[] MarshalSSZ()
        {
            byte[] buf = new byte[SszBytesLen()];
            MarshalSSZTo(buf);
            return buf;
