        public void MarshalSSZTo(Span<byte> buf)
        {
            int offset = 0;
            int fixedStart = offset;

            // Field 'randao_reveal'
            RandaoReveal.MarshalSSZTo(buf.Slice(offset));
            offset += 96;
            // Field 'eth1_data'
            Eth1Data.MarshalSSZTo(buf.Slice(offset));
            offset += 72;
            // Field 'graffiti'
            Graffiti.MarshalSSZTo(buf.Slice(offset));
            offset += 32;
            // Offset placeholder for 'proposer_slashings'
            int offsetPos0 = offset;
            offset += 4;
            // Offset placeholder for 'attester_slashings'
            int offsetPos1 = offset;
            offset += 4;
            // Offset placeholder for 'attestations'
            int offsetPos2 = offset;
            offset += 4;
            // Offset placeholder for 'deposits'
            int offsetPos3 = offset;
            offset += 4;
            // Offset placeholder for 'voluntary_exits'
            int offsetPos4 = offset;
            offset += 4;
            // Field 'sync_aggregate'
            SyncAggregate.MarshalSSZTo(buf.Slice(offset));
            offset += 160;
            // Offset placeholder for 'execution_payload'
            int offsetPos5 = offset;
            offset += 4;
            // Offset placeholder for 'bls_to_execution_changes'
            int offsetPos6 = offset;
            offset += 4;
            // Offset placeholder for 'blob_kzg_commitments'
            int offsetPos7 = offset;
            offset += 4;

            // Dynamic field 'proposer_slashings'
            BinaryPrimitives.WriteUInt32LittleEndian(buf.Slice(offsetPos0), (uint)(offset - fixedStart));
            foreach (var item in ProposerSlashings)
            {
                item.MarshalSSZTo(buf.Slice(offset));
                offset += 416;
            }
            // Dynamic field 'attester_slashings'
            BinaryPrimitives.WriteUInt32LittleEndian(buf.Slice(offsetPos1), (uint)(offset - fixedStart));
            {
                int listStart = offset;
                for (int i = 0; i < AttesterSlashings.Count; i++)
                    offset += 4;
                for (int i = 0; i < AttesterSlashings.Count; i++)
                {
                    BinaryPrimitives.WriteUInt32LittleEndian(buf.Slice(listStart + i * 4), (uint)(offset - listStart));
                    AttesterSlashings[i].MarshalSSZTo(buf.Slice(offset));
                    offset += AttesterSlashings[i].SszBytesLen();
                }
            }
            // Dynamic field 'attestations'
            BinaryPrimitives.WriteUInt32LittleEndian(buf.Slice(offsetPos2), (uint)(offset - fixedStart));
            {
                int listStart = offset;
                for (int i = 0; i < Attestations.Count; i++)
                    offset += 4;
                for (int i = 0; i < Attestations.Count; i++)
                {
                    BinaryPrimitives.WriteUInt32LittleEndian(buf.Slice(listStart + i * 4), (uint)(offset - listStart));
                    Attestations[i].MarshalSSZTo(buf.Slice(offset));
                    offset += Attestations[i].SszBytesLen();
                }
            }
            // Dynamic field 'deposits'
            BinaryPrimitives.WriteUInt32LittleEndian(buf.Slice(offsetPos3), (uint)(offset - fixedStart));
            foreach (var item in Deposits)
            {
                item.MarshalSSZTo(buf.Slice(offset));
                offset += 1240;
            }
            // Dynamic field 'voluntary_exits'
            BinaryPrimitives.WriteUInt32LittleEndian(buf.Slice(offsetPos4), (uint)(offset - fixedStart));
            foreach (var item in VoluntaryExits)
            {
                item.MarshalSSZTo(buf.Slice(offset));
                offset += 112;
            }
            // Dynamic field 'execution_payload'
            BinaryPrimitives.WriteUInt32LittleEndian(buf.Slice(offsetPos5), (uint)(offset - fixedStart));
            ExecutionPayload.MarshalSSZTo(buf.Slice(offset));
            offset += 0;
            // Dynamic field 'bls_to_execution_changes'
            BinaryPrimitives.WriteUInt32LittleEndian(buf.Slice(offsetPos6), (uint)(offset - fixedStart));
            foreach (var item in BlsToExecutionChanges)
            {
                item.MarshalSSZTo(buf.Slice(offset));
                offset += 172;
            }
            // Dynamic field 'blob_kzg_commitments'
            BinaryPrimitives.WriteUInt32LittleEndian(buf.Slice(offsetPos7), (uint)(offset - fixedStart));
            foreach (var item in BlobKzgCommitments)
            {
                item.MarshalSSZTo(buf.Slice(offset));
                offset += 48;
            }
        }

