        public byte[] HashTreeRoot()
        {
            var hh = Hasher.New();
            int idx = hh.Index();

            // Field 'randao_reveal'
            RandaoReveal.HashTreeRootWith(hh);

            // Field 'eth1_data'
            Eth1Data.HashTreeRootWith(hh);

            // Field 'graffiti'
            Graffiti.HashTreeRootWith(hh);

            // Field 'proposer_slashings'
            {
                int subIdx = hh.Index();
                foreach (var item in ProposerSlashings)
                    item.HashTreeRootWith(hh);
                hh.MerkleizeWithMixin(subIdx, (ulong)ProposerSlashings.Count, 16);
            }

            // Field 'attester_slashings'
            {
                int subIdx = hh.Index();
                foreach (var item in AttesterSlashings)
                    item.HashTreeRootWith(hh);
                hh.MerkleizeWithMixin(subIdx, (ulong)AttesterSlashings.Count, 2);
            }

            // Field 'attestations'
            {
                int subIdx = hh.Index();
                foreach (var item in Attestations)
                    item.HashTreeRootWith(hh);
                hh.MerkleizeWithMixin(subIdx, (ulong)Attestations.Count, 128);
            }

            // Field 'deposits'
            {
                int subIdx = hh.Index();
                foreach (var item in Deposits)
                    item.HashTreeRootWith(hh);
                hh.MerkleizeWithMixin(subIdx, (ulong)Deposits.Count, 16);
            }

            // Field 'voluntary_exits'
            {
                int subIdx = hh.Index();
                foreach (var item in VoluntaryExits)
                    item.HashTreeRootWith(hh);
                hh.MerkleizeWithMixin(subIdx, (ulong)VoluntaryExits.Count, 16);
            }

            // Field 'sync_aggregate'
            SyncAggregate.HashTreeRootWith(hh);

            // Field 'execution_payload'
            ExecutionPayload.HashTreeRootWith(hh);

            // Field 'bls_to_execution_changes'
            {
                int subIdx = hh.Index();
                foreach (var item in BlsToExecutionChanges)
                    item.HashTreeRootWith(hh);
                hh.MerkleizeWithMixin(subIdx, (ulong)BlsToExecutionChanges.Count, 16);
            }

            // Field 'blob_kzg_commitments'
            {
                int subIdx = hh.Index();
                foreach (var item in BlobKzgCommitments)
                    item.HashTreeRootWith(hh);
                hh.MerkleizeWithMixin(subIdx, (ulong)BlobKzgCommitments.Count, 4096);
            }

            hh.Merkleize(idx);
            return hh.HashRoot();
        }
