    public class BeaconBlock
    {
        public ulong Slot;
        public ulong ProposerIndex;
        public Bytes32 ParentRoot;
        public Bytes32 StateRoot;
        public BeaconBlockBody Body;

        public BeaconBlock()
        {
            ParentRoot = new Bytes32();
            StateRoot = new Bytes32();
            Body = new BeaconBlockBody();
        }

        public int SszBytesLen()
        {
            int size = 84;
            size += Body.SszBytesLen();
            return size;
        }

        public byte[] MarshalSSZ()
        {
            byte[] buf = new byte[SszBytesLen()];
            MarshalSSZTo(buf);
            return buf;
        }

        public void MarshalSSZTo(Span<byte> buf)
        {
            int offset = 0;
            int fixedStart = offset;

            // Field 'slot'
            BinaryPrimitives.WriteUInt64LittleEndian(buf.Slice(offset), Slot);
            offset += 8;
            // Field 'proposer_index'
            BinaryPrimitives.WriteUInt64LittleEndian(buf.Slice(offset), ProposerIndex);
            offset += 8;
            // Field 'parent_root'
            ParentRoot.MarshalSSZTo(buf.Slice(offset));
            offset += 32;
            // Field 'state_root'
            StateRoot.MarshalSSZTo(buf.Slice(offset));
            offset += 32;
            // Offset placeholder for 'body'
            int offsetPos0 = offset;
            offset += 4;

            // Dynamic field 'body'
            BinaryPrimitives.WriteUInt32LittleEndian(buf.Slice(offsetPos0), (uint)(offset - fixedStart));
            Body.MarshalSSZTo(buf.Slice(offset));
            offset += 0;
        }

        public static BeaconBlock FromSSZBytes(ReadOnlySpan<byte> bytes)
        {
            if (bytes.Length < 84)
                throw new SszError("buffer too small");

            var t = new BeaconBlock();
            int offset = 0;

            t.Slot = BinaryPrimitives.ReadUInt64LittleEndian(bytes.Slice(offset));
            offset += 8;
            t.ProposerIndex = BinaryPrimitives.ReadUInt64LittleEndian(bytes.Slice(offset));
            offset += 8;
            t.ParentRoot = Bytes32.FromSSZBytes(bytes.Slice(offset, 32));
            offset += 32;
            t.StateRoot = Bytes32.FromSSZBytes(bytes.Slice(offset, 32));
            offset += 32;
            int dynOffset0 = (int)BinaryPrimitives.ReadUInt32LittleEndian(bytes.Slice(offset));
            offset += 4;
            if (dynOffset0 != 84)
                throw new SszError("invalid offset");

            {
                var dynBuf = bytes.Slice(dynOffset0, bytes.Length - dynOffset0);
                t.Body = BeaconBlockBody.FromSSZBytes(dynBuf);
            }

            return t;
        }

        public byte[] HashTreeRoot()
        {
            var hh = Hasher.New();
            int idx = hh.Index();

            // Field 'slot'
            hh.PutUint64(Slot);

            // Field 'proposer_index'
            hh.PutUint64(ProposerIndex);

            // Field 'parent_root'
            ParentRoot.HashTreeRootWith(hh);

            // Field 'state_root'
            StateRoot.HashTreeRootWith(hh);

            // Field 'body'
            Body.HashTreeRootWith(hh);

            hh.Merkleize(idx);
            return hh.HashRoot();
        }
    }

    public class SignedBeaconBlock
    {
        public BeaconBlock Message;
        public Bytes96 Signature;

        public SignedBeaconBlock()
        {
            Message = new BeaconBlock();
            Signature = new Bytes96();
        }

        public int SszBytesLen()
        {
            int size = 100;
            size += Message.SszBytesLen();
            return size;
        }

        public byte[] MarshalSSZ()
        {
            byte[] buf = new byte[SszBytesLen()];
            MarshalSSZTo(buf);
            return buf;
        }

        public void MarshalSSZTo(Span<byte> buf)
        {
            int offset = 0;
            int fixedStart = offset;

            // Offset placeholder for 'message'
            int offsetPos0 = offset;
            offset += 4;
            // Field 'signature'
            Signature.MarshalSSZTo(buf.Slice(offset));
            offset += 96;

            // Dynamic field 'message'
            BinaryPrimitives.WriteUInt32LittleEndian(buf.Slice(offsetPos0), (uint)(offset - fixedStart));
            Message.MarshalSSZTo(buf.Slice(offset));
            offset += 0;
        }

        public static SignedBeaconBlock FromSSZBytes(ReadOnlySpan<byte> bytes)
        {
            if (bytes.Length < 100)
                throw new SszError("buffer too small");

            var t = new SignedBeaconBlock();
            int offset = 0;

            int dynOffset0 = (int)BinaryPrimitives.ReadUInt32LittleEndian(bytes.Slice(offset));
            offset += 4;
            if (dynOffset0 != 100)
                throw new SszError("invalid offset");
            t.Signature = Bytes96.FromSSZBytes(bytes.Slice(offset, 96));
            offset += 96;

            {
                var dynBuf = bytes.Slice(dynOffset0, bytes.Length - dynOffset0);
                t.Message = BeaconBlock.FromSSZBytes(dynBuf);
            }

            return t;
        }

        public byte[] HashTreeRoot()
        {
            var hh = Hasher.New();
            int idx = hh.Index();

            // Field 'message'
            Message.HashTreeRootWith(hh);

            // Field 'signature'
            Signature.HashTreeRootWith(hh);

            hh.Merkleize(idx);
            return hh.HashRoot();
        }
    }

